    switch (funct) {
      case 0x00: // ext
        {
          const pos = shamt;
          const size = rd + 1;
          const mask = (1 << size) - 1;
          this.w(rt, (this.r(rs) >>> pos) & mask);
        }
        break;
      case 0x04: // ins
        {
          const pos = shamt;
          const size = rd + 1 - pos;
          const mask = ((1 << size) - 1) << pos;
          this.w(rt, (this.r(rt) & ~mask) | ((this.r(rs) << pos) & mask));
        }
        break;
      case 0x20: // bshfl
        {
          const bshfl_op = shamt;
          switch (bshfl_op) {
            case 0x02: // wsbh
              {
                const v = this.r(rt);
                this.w(rd, (((v & 0x00ff00ff) << 8) | ((v & 0xff00ff00) >>> 8)) >>> 0);
              }
              break;
            case 0x16: // seb
              this.w(rd, ((this.r(rt) & 0xff) << 24) >> 24);
              break;
            case 0x18: // seh
              this.w(rd, ((this.r(rt) & 0xffff) << 16) >> 16);
              break;
            default:
              console.error(`Unimplemented BSHFL 0x${bshfl_op.toString(16)}`);
              process.exit(1);
          }
        }
        break;
      case 0x3b: // rdhwr
        // Just return 0 for any HWR register
        this.w(rt, 0);
        break;
      default:
        console.error(`Unimplemented SPECIAL3 funct 0x${funct.toString(16)} at PC=0x${this.pc.toString(16)}`);
        process.exit(1);
    }
  }

  // ============== Syscall Handler ==============
  handleSyscall() {
    const syscallNum = this.r(2); // $v0
    const a0 = this.r(4);
    const a1 = this.r(5);
    const a2 = this.r(6);
    const a3 = this.r(7);

    switch (syscallNum) {
      case SYS.read: {
        const fd = a0;
        const buf = a1;
        const count = a2;
        const entry = this.fdMap.get(fd);
        if (!entry) {
          this.w(2, -1 >>> 0);
          break;
        }
        if (entry.type === 'stdio') {
          if (fd === 0) {
            // stdin - return 0 (no data)
            this.w(2, 0);
          } else {
            this.w(2, 0);
          }
        } else if (entry.type === 'file') {
          const data = Buffer.alloc(count);
          try {
            const bytesRead = fs.readSync(entry.hostFd, data, 0, count, entry.position);
            for (let i = 0; i < bytesRead; i++) {
              this.mem.write8(buf + i, data[i]);
            }
            entry.position += bytesRead;
            this.w(2, bytesRead);
          } catch (e) {
            this.w(2, -1 >>> 0);
          }
        }
        break;
      }

      case SYS.write: {
        const fd = a0;
        const buf = a1;
        const count = a2;
        const entry = this.fdMap.get(fd);
        if (!entry) {
          this.w(2, -1 >>> 0);
          break;
        }
        const data = Buffer.alloc(count);
        for (let i = 0; i < count; i++) {
          data[i] = this.mem.read8(buf + i);
        }
        if (entry.type === 'stdio') {
          try {
            const written = fs.writeSync(fd, data);
            this.w(2, written);
          } catch (e) {
            this.w(2, count);
          }
        } else if (entry.type === 'file') {
          try {
            const written = fs.writeSync(entry.hostFd, data, 0, count, entry.position);
            entry.position += written;
            if (entry.position > entry.size) entry.size = entry.position;
            this.w(2, written);
          } catch (e) {
            this.w(2, -1 >>> 0);
          }
        }
        break;
      }

      case SYS.open: {
        const pathname = this.mem.readString(a0);
        const flags = a1;
        const mode = a2;
        try {
          // Map virtual path - if it starts with /, pass through, otherwise relative to /app
          let hostPath = pathname;
          if (pathname === 'doom.wad' || pathname === './doom.wad') {
            hostPath = '/app/doom.wad';
          }
          const hostFlags = translateFlags(flags);
          try {
            fs.accessSync(path.dirname(hostPath));
          } catch (e) {
            // directory might not exist
          }
          const hostFd = fs.openSync(hostPath, hostFlags, mode || 0o644);
          const fd = this.nextFd++;
          let size = 0;
          try {
            const stat = fs.fstatSync(hostFd);
            size = stat.size;
          } catch (e) {}
          this.fdMap.set(fd, { type: 'file', hostFd, position: 0, size, path: hostPath });
          this.w(2, fd);
        } catch (e) {
          this.w(2, -1 >>> 0);
        }
        break;
      }

      case SYS.close: {
        const fd = a0;
        const entry = this.fdMap.get(fd);
        if (!entry) {
          this.w(2, -1 >>> 0);
          break;
        }
        if (entry.type === 'file') {
          try {
            fs.closeSync(entry.hostFd);
          } catch (e) {}
        }
        this.fdMap.delete(fd);
        this.w(2, 0);
        break;
      }

      case SYS.lseek: {
        const fd = a0;
        const offset = this.sr(5); // signed
        const whence = a2;
        const entry = this.fdMap.get(fd);
        if (!entry || entry.type !== 'file') {
          this.w(2, -1 >>> 0);
          break;
        }
        let newPos;
        switch (whence) {
          case 0: newPos = offset; break; // SEEK_SET
          case 1: newPos = entry.position + offset; break; // SEEK_CUR
          case 2: newPos = entry.size + offset; break; // SEEK_END
          default: newPos = -1; break;
        }
        if (newPos < 0) {
          this.w(2, -1 >>> 0);
        } else {
          entry.position = newPos;
          this.w(2, newPos >>> 0);
        }
